INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 7, 0.0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", -363.0, 7001, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 7, 0.0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", -363.0, 7002, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 7, 0.0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", -363.0, 7003, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 10, 0.0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", -363.0, 10001, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 10, 0.0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", -363.0, 10002, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 10, 0.0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", -363.0, 10003, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 10, 0.0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", -363.0, 10004, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 12, 0.0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", -416.5, 12001, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 13, 0.0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", -363.0, 13001, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 13, 0.0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", -363.0, 13002, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 13, 0.0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", -363.0, 13003, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 13, 0.0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", -363.0, 13004, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 14, 0.0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", -363.0, 14001, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 14, 0.0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", -363.0, 14002, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 14, 0.0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", -363.0, 14003, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 14, 0.0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", -363.0, 14004, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 15, 0.0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", -470.0, 15001, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 16, 0.0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", -363.0, 16001, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 16, 0.0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", -363.0, 16002, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 16, 0.0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", -363.0, 16003, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 16, 0.0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", -363.0, 16004, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 17, 0.0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", -363.0, 17002, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 25, 0.0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", -363.0, 17004, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 25, 0.0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", -363.0, 17005, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 25, 0.0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", -363.0, 17006, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 25, 0.0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", -363.0, 17007, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 18, 0.0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", -363.0, 18001, 1, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 18, 0.0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", -363.0, 18002, 2, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 19, 0.0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", -470.0, 19001, 3, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 19, 0.0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", -470.0, 19002, 4, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 20, 0.0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", -470.0, 20001, 5, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 20, 0.0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", -470.0, 20002, 6, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 21, 0.0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", -363.0, 21001, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 21, 0.0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", -363.0, 21002, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 21, 0.0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", -363.0, 21003, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 21, 0.0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", -363.0, 21004, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 22, 0.0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", -430.0, 22001, 1, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 22, 0.0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", -430.0, 22002, 2, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 23, 0.0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", -430.0, 23001, 3, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 23, 0.0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", -430.0, 23002, 4, "カリン", 190801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", -385.0, 24001, 1, "エリコ（バレンタイン）", 109001, 10011, 4.08, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", -385.0, 24002, 2, "エリコ（バレンタイン）", 109001, 10011, 5.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", -385.0, 24003, 3, "エリコ（バレンタイン）", 109001, 10011, 10.11, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", -385.0, 24004, 4, "エリコ（バレンタイン）", 109001, 10011, 4.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", -385.0, 24005, 5, "エリコ（バレンタイン）", 109001, 10011, 6.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 0.0, 24006, 6, "エリコ（バレンタイン）", 109002, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 0.0, 24007, 7, "エリコ（バレンタイン）", 109002, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 0.0, 24008, 8, "エリコ（バレンタイン）", 109002, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 0.0, 24009, 9, "エリコ（バレンタイン）", 109002, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 0.0, 24010, 10, "エリコ（バレンタイン）", 109002, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", -385.0, 24011, 1, "シズル（バレンタイン）", 109101, 10011, 2.12, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 5, "2030/12/17 14:59:59", 2, 24, 8.0, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", -385.0, 24012, 2, "シズル（バレンタイン）", 109101, 10011, 4.19, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 2, "2030/12/17 14:59:59", 4, 24, 8.0, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", -385.0, 24013, 3, "シズル（バレンタイン）", 109101, 10011, 2.3, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 0.0, 24014, 4, "シズル（バレンタイン）", 109102, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 5, "2030/12/17 14:59:59", 2, 24, 8.0, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", -385.0, 24015, 5, "シズル（バレンタイン）", 109101, 10011, 5.23, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 0.0, 24016, 6, "シズル（バレンタイン）", 109102, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", -385.0, 24017, 7, "シズル（バレンタイン）", 109101, 10011, 5.01, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 0.0, 24018, 8, "シズル（バレンタイン）", 109102, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 0.0, 24019, 9, "シズル（バレンタイン）", 109102, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/01/31 12:00:00", 1, "2030/12/17 14:59:59", 1, 24, 0.0, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 0.0, 24020, 10, "シズル（バレンタイン）", 109102, 10011, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 26, 0.0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", -363.0, 26001, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 26, 0.0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", -363.0, 26002, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 26, 0.0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", -363.0, 26003, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 26, 0.0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", -363.0, 26004, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 1, 27, 0.0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", -363.0, 27001, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 27, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", -363.0, 27002, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 27, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", -363.0, 27003, 1, "キャル", 106001, 0, 0.0, 0);
