INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2019/09/24 15:00:00", 1, "2030/12/17 14:59:59", 1, 28, 0.0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", -363.0, 28001, 1, "カリン", 190801, 0, 0.0, 0);
