INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 41, 0.0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", -363.0, 41003, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 41, 0.0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", -363.0, 41004, 1, "コッコロ", 105901, 0, 0.0, 0);
