INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 42, 0.0, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", -416.5, 42002, 1, "シェフィ", 106401, 0, 0.0, 2104010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 42, 0.0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", -416.5, 42003, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 42, 0.0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", -416.5, 42004, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 43, 0.0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", -363.0, 43001, 1, "ペコリーヌ", 105801, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 43, 0.0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", -363.0, 43002, 1, "コッコロ", 105901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 43, 0.0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", -363.0, 43003, 1, "キャル", 106001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 44, 0.0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", -416.5, 43004, 1, "アメス", 123001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 44, 0.0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", -416.5, 43005, 2, "アメス", 123001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 2, 45, 0.0, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", -416.5, 43006, 3, "アメス", 123001, 0, 5.79, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 1, 46, 0.0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", -371.5, 46001, 1, "アメス", 123001, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 2, "2030/12/17 14:59:59", 2, 47, 0.0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", -416.5, 47001, 1, "シズル", 104901, 0, 0.0, 0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("2015/12/17 15:00:00", 1, "2030/12/17 14:59:59", 2, 47, 0.0, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", -416.5, 47002, 1, "リノ", 101101, 0, 9.32, 0);
